import { Model, Schema, model, models } from "mongoose";

export type BannerDocument = {
  _id: string;
  projectName: string;
  title: string;
  subtitle: string;
  imageUrl: string;
  ctaLabel: string;
  ctaHref: string;
  updatedBy: string;
  createdAt: Date;
  updatedAt: Date;
};

const BannerSchema = new Schema<BannerDocument>(
  {
    projectName: { type: String, required: true, trim: true },
    title: { type: String, required: true, trim: true },
    subtitle: { type: String, required: true, trim: true },
    imageUrl: { type: String, required: true, trim: true },
    ctaLabel: { type: String, required: true, trim: true },
    ctaHref: { type: String, required: true, trim: true },
    updatedBy: { type: String, required: true },
  },
  { timestamps: true }
);

export const BannerModel: Model<BannerDocument> =
  (models.Banner as Model<BannerDocument> | undefined) ??
  model<BannerDocument>("Banner", BannerSchema);
